 18→const formatJsonWithPreservedWhitespace = (obj: any): string => {
 19→	return JSON.stringify(obj, null, 2)
 20→		.replace(/\\\\n/g, '\\n')
 21→		.replace(/\\n/g, '\n')
 22→		.replace(/\\\\t/g, '\\t')
 23→		.replace(/\\t/g, '\t');
 24→};
