 93→const CodeBlock = ({
 94→	content,
 95→	language = '',
 96→	isError = false,
 97→}: {
 98→	content: string;
 99→	language?: string;
100→	isError?: boolean;
101→}) => {
102→	const [isTruncated, setIsTruncated] = useState(content.length > 500);
103→	const codeRef = useRef<HTMLElement>(null);
104→
105→	useEffect(() => {
106→		if (codeRef.current && (globalThis as any).hljs) {
107→			(globalThis as any).hljs.highlightElement(codeRef.current);
108→		}
109→	}, [content, isTruncated]);
110→
111→	return (
112→		<div style={{ position: 'relative', marginBottom: '1rem' }}>
113→			<pre
114→				style={{
115→					margin: 0,
116→					padding: '1rem',
117→					backgroundColor: isError ? '#fef2f2' : '#1e1e1e',
118→					color: isError ? '#991b1b' : '#d4d4d4',
119→					borderRadius: '6px',
120→					overflow: isTruncated ? 'hidden' : 'auto',
121→					fontSize: '0.875rem',
122→					fontFamily: 'monospace',
123→					border: isError ? '1px solid #fecaca' : 'none',
124→					maxHeight: isTruncated ? '300px' : 'none',
125→					position: 'relative',
126→					whiteSpace: 'pre-wrap',
127→					wordBreak: 'break-word',
128→				}}
129→			>
130→				<code ref={codeRef} className={language ? `language-${language}` : ''}>
131→					{content}
132→				</code>
133→				{isTruncated && content.length > 500 && (
134→					<div
135→						style={{
136→							position: 'absolute',
137→							bottom: 0,
138→							left: 0,
139→							right: 0,
140→							height: '60px',
141→							background: isError
142→								? 'linear-gradient(transparent, #fef2f2)'
143→								: 'linear-gradient(transparent, #1e1e1e)',
144→							pointerEvents: 'none',
145→						}}
146→					/>
147→				)}
148→			</pre>
149→			{content.length > 500 && (
150→				<button
151→					onClick={() => setIsTruncated(!isTruncated)}
152→					style={{
153→						marginTop: '0.5rem',
154→						padding: '0.5rem 1rem',
155→						backgroundColor: '#3b82f6',
156→						color: 'white',
157→						border: 'none',
158→						borderRadius: '4px',
159→						cursor: 'pointer',
160→						fontSize: '0.875rem',
161→					}}
162→				>
163→					{isTruncated ? 'Show more' : 'Show less'}
164→				</button>
165→			)}
166→		</div>
167→	);
168→};
