217→const FileDiff = ({
218→	filePath,
219→	oldString,
220→	newString,
221→}: {
222→	filePath: string;
223→	oldString: string;
224→	newString: string;
225→}) => {
226→	const diff = `--- a/${filePath}
227→+++ b/${filePath}
228→@@ -1,${oldString.split('\n').length} +1,${newString.split('\n').length} @@
229→${oldString
230→	.split('\n')
231→	.map((line) => '-' + line)
232→	.join('\n')}
233→${newString
234→	.split('\n')
235→	.map((line) => '+' + line)
236→	.join('\n')}`;
237→
238→	return (
239→		<>
240→			<ContentSection label="File Path">
241→				<code
242→					style={{
243→						background: '#f9f9f9',
244→						padding: '0.25rem 0.5rem',
245→						borderRadius: '4px',
246→						fontSize: '0.875rem',
247→						fontFamily: 'monospace',
248→					}}
249→				>
250→					{filePath}
251→				</code>
252→			</ContentSection>
253→			<ContentSection label="Diff">
254→				<CodeBlock content={diff} language="diff" />
255→			</ContentSection>
256→		</>
257→	);
258→};
