328→const TYPE_COLORS = {
329→	assistant: { bg: '#dbeafe', text: '#1e40af' },
330→	user: { bg: '#f3e8ff', text: '#6b21a8' },
331→	system: { bg: '#e0e7ff', text: '#3730a3' },
332→	result: { bg: '#dcfce7', text: '#166534' },
