337→const Turn = ({
338→	children,
339→	type,
340→	title,
341→	subtitle,
342→	tokenCount,
343→	percentage,
344→	isMCP = false,
345→}: {
346→	children: React.ReactNode;
347→	type: keyof typeof TYPE_COLORS;
348→	title: string;
349→	subtitle?: string;
350→	tokenCount?: string;
351→	percentage?: number;
352→	isMCP?: boolean;
353→}) => {
354→	const [isExpanded, setIsExpanded] = useState(false);
355→
356→	const colors = TYPE_COLORS[type] ?? TYPE_COLORS.assistant;
357→
358→	return (
359→		<div
360→			style={{
361→				marginBottom: '1rem',
362→				border: isMCP ? '2px solid #06b6d4' : '1px solid #e5e7eb',
363→				borderRadius: '8px',
364→				overflow: 'hidden',
