371→					alignItems: 'center',
372→					gap: '0.75rem',
373→					padding: '1rem',
374→					backgroundColor: '#f9fafb',
375→					cursor: 'pointer',
376→					userSelect: 'none',
377→				}}
378→			>
379→				<div
380→					style={{
381→						transform: isExpanded ? 'rotate(90deg)' : 'rotate(0deg)',
382→						transition: 'transform 0.2s',
383→						fontSize: '0.75rem',
384→					}}
385→				>
386→					▶
387→				</div>
388→				<span
389→					style={{
390→						padding: '0.25rem 0.75rem',
391→						borderRadius: '4px',
392→						fontSize: '0.75rem',
393→						fontWeight: 600,
394→						backgroundColor: colors.bg,
395→						color: colors.text,
396→						textTransform: 'uppercase',
397→					}}
398→				>
399→					{type}
400→				</span>
401→				{isMCP && (
402→					<span
403→						style={{
404→							padding: '0.25rem 0.5rem',
405→							borderRadius: '4px',
406→							fontSize: '0.75rem',
407→							fontWeight: 600,
408→							backgroundColor: '#06b6d4',
409→							color: 'white',
410→						}}
411→					>
412→						MCP
413→					</span>
414→				)}
415→				<span style={{ fontWeight: 600 }}>{title}</span>
416→				{subtitle && (
417→					<span
418→						style={{
419→							color: '#6b7280',
420→							fontSize: '0.875rem',
421→							fontFamily: 'monospace',
422→							flex: 1,
423→						}}
424→					>
425→						{subtitle}
426→					</span>
427→				)}
428→				{!subtitle && <span style={{ flex: 1 }} />}
429→				{tokenCount && (
430→					<>
431→						<span style={{ flex: 1 }} />
432→						<span style={{ fontSize: '0.875rem', color: '#6b7280' }}>{tokenCount}</span>
433→						{percentage !== undefined && (
434→							<span
435→								style={{
436→									...getPercentageStyle(percentage),
437→									padding: '0.125rem 0.5rem',
438→									borderRadius: '9999px',
439→									fontSize: '0.75rem',
440→									fontWeight: 600,
441→								}}
442→							>
443→								{percentage.toFixed(1)}%
444→							</span>
445→						)}
446→					</>
447→				)}
448→			</div>
449→			{isExpanded && <div style={{ padding: '1rem', backgroundColor: 'white' }}>{children}</div>}
450→		</div>
451→	);
