453→
454→export const Transcript = (props: TranscriptProps) => {
455→	const { prompt, promptTokenCount, messages } = props;
456→
457→	useEffect(() => {
458→		const script = document.createElement('script');
459→		script.type = 'module';
460→		script.textContent = `import hljs from 'https://esm.sh/highlight.js@11.9.0'; window.hljs = hljs;`;
461→		document.head.appendChild(script);
462→
463→		const style = document.createElement('link');
464→		style.rel = 'stylesheet';
465→		style.href = 'https://esm.sh/highlight.js@11.9.0/styles/github-dark-dimmed.css';
466→		document.head.appendChild(style);
467→
468→		const codeStyle = document.createElement('style');
469→		codeStyle.textContent = 'code * { font-family: monospace !important; }';
470→		document.head.appendChild(codeStyle);
471→
472→		return () => {
473→			document.head.removeChild(script);
474→			document.head.removeChild(style);
475→			document.head.removeChild(codeStyle);
476→		};
477→	}, []);
478→
479→	const systemTurn = messages.find((t) => t.type === 'system') as SystemMessage | undefined;
480→	const resultTurn = messages.find((t) => t.type === 'result') as ResultMessage | undefined;
481→
482→	const messageTokens = messages.reduce((sum, turn) => sum + (turn.tokenCount || 0), 0);
483→
484→	const totalTime = messages.reduce((sum, turn) => sum + (turn.ms || 0), 0);
485→	const totalMessageTokens = messageTokens;
486→
487→	const metadataCards = [];
488→
489→	if (systemTurn) {
490→		metadataCards.push({
491→			title: 'Agent',
492→			value: systemTurn.agent || 'N/A',
493→		});
494→
495→		metadataCards.push({
496→			title: 'Model',
497→			value: systemTurn.model || 'N/A',
498→		});
499→
500→		if (systemTurn.tools) {
501→			const mcpTools = systemTurn.tools.filter((t) => t.includes('mcp'));
502→			metadataCards.push({
503→				title: 'Available Tools',
504→				value: systemTurn.tools.length,
505→				subvalue: mcpTools.length > 0 ? `${mcpTools.length} MCP tools` : 'unknown',
506→			});
507→		}
508→
509→		if (systemTurn.mcp_servers && systemTurn.mcp_servers.length > 0) {
510→			const mcpServersHtml =
511→				'<div style="display: flex; flex-wrap: wrap;">' +
512→				systemTurn.mcp_servers
513→					.map(
514→						(s) =>
515→							`<div style="display: inline-flex; align-items: center; padding: 0.25rem 0.75rem; background-color: #f3f4f6; border-radius: 9999px; font-size: 0.875rem; margin-right: 0.5rem; margin-bottom: 0.5rem;">
516→								<span title="${s.status}" style="width: 8px; height: 8px; border-radius: 50%; background-color: ${s.status === 'connected' ? '#10b981' : s.status === 'unknown' ? '#6b7280' : '#ef4444'}; margin-right: 0.5rem;"></span>
517→								${s.name}
518→							</div>`,
519→					)
520→					.join('') +
521→				'</div>';
522→			metadataCards.push({
523→				title: 'MCP Servers',
524→				html: mcpServersHtml,
525→			});
526→		} else {
527→			metadataCards.push({
528→				title: 'MCP Servers',
529→				value: 'None',
530→			});
531→		}
532→	}
533→
534→	if (resultTurn) {
535→		if (resultTurn.num_turns !== undefined) {
536→			metadataCards.push({
537→				title: 'Turns',
538→				value: resultTurn.num_turns,
539→			});
540→		}
541→
542→		if (messageTokens > 0) {
543→			metadataCards.push({
544→				title: 'Total Message Tokens',
545→				value: messageTokens.toLocaleString(),
546→			});
547→		}
548→	}
549→
550→	const turns = messages.filter((t) => ['assistant', 'user', 'system', 'result'].includes(t.type));
551→
552→	const groupedTurns = groupToolCallsWithResults(turns);
553→
554→	return (
555→		<div style={{ fontFamily: 'system-ui, sans-serif', padding: '2rem' }}>
556→			<h1 style={{ marginTop: 0 }}>Agent Transcript</h1>
557→
558→			{metadataCards.length > 0 && (
559→				<div style={{ marginBottom: '2rem' }}>
560→					<h2
561→						style={{
562→							fontSize: '1.125rem',
563→							fontWeight: 600,
564→							marginBottom: '1rem',
565→						}}
566→					>
567→						Metadata
568→					</h2>
569→					<div
570→						style={{
571→							display: 'grid',
572→							gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
573→							gap: '1rem',
574→						}}
575→					>
576→						{metadataCards.map((card, index) => (
577→							<MetadataCard key={index} {...card} />
578→						))}
579→					</div>
580→				</div>
581→			)}
582→
583→			<h2
584→				style={{
585→					fontSize: '1.125rem',
586→					fontWeight: 600,
587→					marginBottom: '1rem',
588→				}}
589→			>
590→				Turns
591→			</h2>
592→
593→			{prompt && (
594→				<Turn
595→					type="prompt"
596→					title="User Prompt"
597→					tokenCount={`${promptTokenCount.toLocaleString()} tokens`}
598→					percentage={(promptTokenCount / totalMessageTokens) * 100}
599→				>
600→					<ContentSection label="Prompt">
601→						<CodeBlock content={prompt} language="markdown" />
602→					</ContentSection>
603→				</Turn>
604→			)}
605→
606→			{groupedTurns.map((group, index) => {
607→				const isTodoWrite =
608→					group.toolCall &&
609→					'message' in group.toolCall &&
610→					group.toolCall.message?.content?.find(
611→						(c) => c.type === 'tool_use' && c.name === 'TodoWrite',
612→					);
613→
614→				if (isTodoWrite && 'input' in isTodoWrite && isTodoWrite.input?.todos) {
615→					return <TodoList key={index} todos={isTodoWrite.input.todos} />;
616→				}
617→
618→				const elements = [];
619→
620→				if (index > 0) {
621→					const currentTurn = group.toolCall || group.turn;
622→					if (currentTurn) {
623→						const elapsedMs = currentTurn.ms;
624→						if (elapsedMs >= 50) {
625→							const percentage = (elapsedMs / totalTime) * 100;
626→							elements.push(
627→								<ElapsedTime
628→									key={`elapsed-${index}`}
629→									elapsedMs={elapsedMs}
630→									percentage={percentage}
631→								/>,
632→							);
633→						}
634→					}
635→				}
636→
637→				if (group.toolCall && group.toolResult) {
638→					elements.push(
639→						<ToolCallGroup
640→							key={`tool-${index}`}
641→							toolCall={group.toolCall as AssistantMessage}
642→							toolResult={group.toolResult as UserMessage}
643→							totalMessageTokens={totalMessageTokens}
644→							cwd={systemTurn?.cwd || ''}
645→						/>,
646→					);
647→				} else if (group.turn) {
648→					elements.push(
649→						<TurnRenderer
650→							key={`turn-${index}`}
651→							turn={group.turn}
652→							totalMessageTokens={totalMessageTokens}
653→						/>,
654→					);
655→				}
656→
657→				return elements;
658→			})}
659→		</div>
660→	);
661→};
662→
663→function groupToolCallsWithResults(turns: TranscriptMessage[]): Array<{
664→	toolCall?: TranscriptMessage;
665→	toolResult?: TranscriptMessage;
666→	turn?: TranscriptMessage;
667→}> {
668→	const grouped: Array<{
669→		toolCall?: TranscriptMessage;
670→		toolResult?: TranscriptMessage;
671→		turn?: TranscriptMessage;
672→	}> = [];
673→	const usedResultIndices = new Set<number>();
674→
675→	for (const [i, turn] of turns.entries()) {
676→		if (usedResultIndices.has(i)) continue;
677→
678→		const toolUseContent =
679→			turn.type === 'assistant' &&
680→			'message' in turn &&
681→			turn.message?.content?.find((c) => c.type === 'tool_use');
682→
683→		if (toolUseContent && 'id' in toolUseContent) {
684→			const toolUseId = toolUseContent.id;
685→			const resultIndex = turns.findIndex(
686→				(t, j) =>
687→					j > i &&
688→					t.type === 'user' &&
689→					'message' in t &&
690→					t.message?.content?.some(
691→						(c) => c.type === 'tool_result' && 'tool_use_id' in c && c.tool_use_id === toolUseId,
692→					),
693→			);
694→
695→			if (resultIndex !== -1) {
696→				grouped.push({ toolCall: turn, toolResult: turns[resultIndex] });
697→				usedResultIndices.add(resultIndex);
698→				continue;
699→			}
700→		}
701→
702→		grouped.push({ turn });
703→	}
704→
705→	return grouped;
706→}
707→
708→const ToolCallGroup = ({
709→	toolCall,
710→	toolResult,
711→	totalMessageTokens,
712→	cwd,
713→}: {
714→	toolCall: AssistantMessage;
715→	toolResult: UserMessage;
716→	totalMessageTokens: number;
717→	cwd: string;
718→}) => {
719→	const toolUse = toolCall.message.content.find((c) => c.type === 'tool_use') as ToolUseContent;
720→	const toolName = toolUse?.name || 'Unknown Tool';
721→	const isMCP = toolUse?.isMCP;
722→
723→	const additionalInfo = extractToolAdditionalInfo(toolUse, toolName, cwd);
724→
725→	const totalTokens = (toolCall.tokenCount || 0) + (toolResult.tokenCount || 0);
726→	const percentage = totalMessageTokens > 0 ? (totalTokens / totalMessageTokens) * 100 : 0;
727→
728→	const tokenCountStr =
729→		toolCall.tokenCount && toolResult.tokenCount
730→			? `${toolCall.tokenCount.toLocaleString()} + ${toolResult.tokenCount.toLocaleString()} tokens`
731→			: `${totalTokens.toLocaleString()} tokens`;
732→
733→	return (
734→		<Turn
735→			type="tool"
736→			title={toolName}
737→			subtitle={additionalInfo}
738→			tokenCount={tokenCountStr}
739→			percentage={percentage}
740→			isMCP={isMCP}
741→		>
742→			{renderToolInput(toolUse, toolName)}
743→			{renderToolOutput(toolResult, isMCP)}
744→		</Turn>
745→	);
746→};
747→
748→const TurnRenderer = ({
749→	turn,
750→	totalMessageTokens,
751→}: {
752→	turn: TranscriptMessage;
753→	totalMessageTokens: number;
754→}) => {
755→	const isMCP =
756→		turn.type === 'assistant' &&
757→		'message' in turn &&
758→		turn.message?.content?.some((c) => c.type === 'tool_use' && c.isMCP);
759→
760→	const title = getTurnTitle(turn);
761→	const percentage =
762→		turn.tokenCount && totalMessageTokens > 0 ? (turn.tokenCount / totalMessageTokens) * 100 : 0;
763→
764→	return (
765→		<Turn
766→			type={turn.type}
767→			title={title}
768→			tokenCount={turn.tokenCount ? `${turn.tokenCount.toLocaleString()} tokens` : undefined}
769→			percentage={turn.tokenCount ? percentage : undefined}
770→			isMCP={isMCP}
771→		>
772→			{'message' in turn && turn.message?.content
773→				? renderTurnContent(turn.message.content)
774→				: renderSystemOrResult(turn)}
775→		</Turn>
776→	);
777→};
778→
779→function getTurnTitle(turn: TranscriptMessage): string {
780→	if (turn.type === 'assistant' && 'message' in turn && turn.message?.content) {
781→		const toolUse = turn.message.content.find((c) => c.type === 'tool_use');
782→		if (toolUse && 'name' in toolUse) return toolUse.name;
783→
784→		const text = turn.message.content.find((c) => c.type === 'text');
785→		if (text && 'text' in text) return truncateText(text.text, 80);
786→	}
787→
788→	if (turn.type === 'user' && 'message' in turn && turn.message?.content) {
789→		const toolResult = turn.message.content.find((c) => c.type === 'tool_result');
790→		if (toolResult && 'tool_use_id' in toolResult) return `Result: ${toolResult.tool_use_id}`;
791→	}
792→
793→	return 'subtype' in turn && turn.subtype ? turn.subtype : turn.type;
794→}
795→
796→function extractToolAdditionalInfo(
797→	toolUse: ToolUseContent | undefined,
798→	toolName: string,
799→	cwd: string,
800→): string {
801→	if (!toolUse?.input) return '';
802→
803→	if (['Read', 'Write', 'Edit'].includes(toolName)) {
804→		const fullPath = toolUse.input.file_path || toolUse.input.path;
805→		if (fullPath) {
806→			return cwd && fullPath.startsWith(cwd)
807→				? fullPath.substring(cwd.length).replace(/^\//, '')
808→				: fullPath;
809→		}
810→	}
811→
812→	if (toolName === 'Glob' && toolUse.input.pattern) {
813→		return toolUse.input.pattern;
814→	}
815→
816→	if (toolName === 'Bash' && toolUse.input.command) {
817→		const cmd = toolUse.input.command;
818→		return cmd.length > 80 ? cmd.slice(0, 80) + '...' : cmd;
819→	}
820→
821→	return '';
822→}
823→
824→function renderToolInput(toolUse: ToolUseContent | undefined, toolName: string): React.ReactNode {
825→	if (!toolUse?.input) return null;
826→
827→	if (toolName === 'Write' && toolUse.input.file_path && toolUse.input.content) {
828→		return (
829→			<FileContent
830→				filePath={toolUse.input.file_path}
831→				content={toolUse.input.content}
832→				language="typescript"
833→			/>
834→		);
835→	}
836→
837→	if (
838→		toolName === 'Edit' &&
839→		toolUse.input.file_path &&
840→		toolUse.input.old_string &&
841→		toolUse.input.new_string
842→	) {
843→		return (
844→			<FileDiff
845→				filePath={toolUse.input.file_path}
846→				oldString={toolUse.input.old_string}
847→				newString={toolUse.input.new_string}
848→			/>
849→		);
850→	}
851→
852→	return (
853→		<ContentSection label="Input">
854→			<CodeBlock content={formatJsonWithPreservedWhitespace(toolUse.input)} />
855→		</ContentSection>
856→	);
857→}
858→
859→function renderToolOutput(toolResult: UserMessage, isMCP: boolean): React.ReactNode {
860→	const toolResultContent = toolResult.message.content.find((c) => c.type === 'tool_result');
861→	if (!toolResultContent) return null;
862→
863→	if (isMCP) {
864→		try {
865→			const content =
866→				typeof toolResultContent.content === 'string'
867→					? JSON.parse(toolResultContent.content)
868→					: toolResultContent.content;
869→
870→			if (Array.isArray(content)) {
871→				return (
872→					<ContentSection label="Output">
873→						<>
874→							{content.map((item, index) => {
875→								if (item.type !== 'text' || !item.text) return null;
876→								return <CodeBlock key={index} content={item.text} isError={item.isError} />;
877→							})}
878→						</>
879→					</ContentSection>
880→				);
881→			}
882→		} catch {
883→			// Fall through to default rendering
884→		}
885→	}
886→
887→	return (
888→		<ContentSection label="Output">
889→			<CodeBlock
890→				content={
891→					typeof toolResultContent.content === 'string'
892→						? toolResultContent.content
893→						: JSON.stringify(toolResultContent.content, null, 2)
894→				}
895→			/>
896→		</ContentSection>
897→	);
898→}
899→
900→function renderTurnContent(
901→	content: (TextContent | ToolUseContent | ToolResultContent)[],
902→): React.ReactNode {
903→	return (
904→		<>
905→			{content.map((item, index) => {
906→				if (item.type === 'text' && 'text' in item) {
907→					return (
908→						<ContentSection key={index} label="Text">
909→							<CodeBlock content={item.text} language="markdown" />
910→						</ContentSection>
911→					);
912→				}
913→				if (item.type === 'tool_use' && 'name' in item) {
914→					return (
915→						<div key={index}>
916→							<ContentSection label="Tool">
917→								<code
918→									style={{
919→										background: '#f9f9f9',
920→										padding: '0.25rem 0.5rem',
921→										borderRadius: '4px',
922→										fontSize: '0.875rem',
923→										fontFamily: 'monospace',
924→									}}
925→								>
926→									{item.name}
927→								</code>
928→							</ContentSection>
929→							{'input' in item && item.input && (
930→								<ContentSection label="Input">
931→									<CodeBlock content={formatJsonWithPreservedWhitespace(item.input)} />
932→								</ContentSection>
933→							)}
934→						</div>
935→					);
936→				}
937→				if (item.type === 'tool_result' && 'content' in item) {
938→					return (
939→						<ContentSection key={index} label="Result">
940→							<CodeBlock
941→								content={
942→									typeof item.content === 'string'
943→										? item.content
944→										: JSON.stringify(item.content, null, 2)
945→								}
946→							/>
947→						</ContentSection>
948→					);
949→				}
950→				return null;
951→			})}
952→		</>
953→	);
954→}
955→
956→function renderSystemOrResult(turn: TranscriptMessage): React.ReactNode {
957→	const data = { ...turn };
958→	delete (data as any).type;
959→	delete (data as any).ms;
960→	delete (data as any).uuid;
961→	delete (data as any).session_id;
962→	delete (data as any).parent_tool_use_id;
963→	delete (data as any).tokenCount;
964→	delete (data as any).costUSD;
965→
966→	return (
967→		<ContentSection label="Data">
968→			<CodeBlock content={formatJsonWithPreservedWhitespace(data)} />
969→		</ContentSection>
970→	);
971→}
