 1→import { useRef, useState } from "react";
 2→import styled from "@emotion/styled";
 3→import { GuideCue, GuideCueProps } from "@leafygreen-ui/guide-cue";
 4→import { palette } from "@leafygreen-ui/palette";
 5→import { differenceInDays } from "date-fns";
 6→import Cookies from "js-cookie";
 7→import { size } from "../../constants/tokens";
 8→import Icon from "../Icon";
 9→
10→type Props = {
11→  activeDays?: number;
12→  cookieName: string;
13→  loading?: boolean;
14→};
15→
16→/**
17→ * ExpiringAnnouncementTooltip displays a clickable info icon with a popover.
18→ * On first view, the popover opens automatically. Once dismissed, a cookie is set
19→ * and the popover stays closed on future visits. The info icon remains visible
20→ * for `activeDays` (default 8) after first dismissal, then disappears entirely.
21→ * @param props - React props
22→ * @param props.activeDays - number of days the info icon will persist after the tooltip is first viewed
23→ * @param props.cookieName - cookie associated with the view state
24→ * @param props.loading - whether data present in the tooltip is loading, helps avoid flickering tooltip
25→ * @returns React component
26→ */
27→export const ExpiringAnnouncementTooltip: React.FC<
28→  Props & Pick<GuideCueProps, "children" | "title" | "tooltipAlign">
29→> = ({ activeDays = 8, cookieName, loading = false, ...guideCueProps }) => {
30→  const now = new Date();
31→  const infoRef = useRef(null);
32→
33→  const seenTooltipCookie: string | undefined = Cookies.get(cookieName);
34→  const neverSeenTooltip = !seenTooltipCookie;
35→  const seenTooltipDate = seenTooltipCookie ? new Date(seenTooltipCookie) : now;
36→
37→  const [open, setOpen] = useState(neverSeenTooltip);
38→
39→  const close = () => {
40→    setOpen(false);
41→
42→    if (neverSeenTooltip) {
43→      Cookies.set(cookieName, seenTooltipDate.toString(), { expires: 365 });
44→    }
45→  };
46→
47→  return !loading &&
48→    (neverSeenTooltip ||
49→      differenceInDays(now, seenTooltipDate) < activeDays) ? (
50→    <>
51→      <IconContainer ref={infoRef}>
52→        <Icon
53→          data-cy="announcement-tooltip-trigger"
54→          fill={palette.gray.dark2}
55→          glyph="InfoWithCircle"
56→          onClick={() => setOpen((o) => !o)}
57→        />
58→      </IconContainer>
59→      <GuideCue
60→        currentStep={1}
61→        numberOfSteps={1}
62→        onDismiss={close}
63→        onPrimaryButtonClick={close}
64→        open={open}
65→        refEl={infoRef}
66→        setOpen={setOpen}
67→        {...guideCueProps}
68→      />
69→    </>
70→  ) : null;
71→};
72→
73→const IconContainer = styled.div`
74→  cursor: pointer;
75→  padding-left: ${size.xxs};
76→`;
