import {
  ReactNode,
  createContext,
  useCallback,
  useContext,
  useMemo,
} from "react";
import {
  ToastProvider as LGToastProvider,
  Variant,
  useToast,
} from "@leafygreen-ui/toast";
import { WordBreak } from "../../components/styles";
import {
  TOAST_TIMEOUT,
  mapLeafyGreenVariantToTitle,
  mapLeafyGreenVariantToToast,
} from "./constants";
import { DispatchToast, DispatchToastWithProgress, ToastParams } from "./types";

interface ToastContextState {
  success: DispatchToast;
  warning: DispatchToast;
  error: DispatchToast;
  info: DispatchToast;
  progress: DispatchToastWithProgress;
}

export const ToastContext = createContext<ToastContextState | null>(null);

const useToastContext = (): ToastContextState => {
  const context = useContext(ToastContext);
  if (context === null || context === undefined) {
    throw new Error("useToastContext must be used within a ToastProvider");
  }
  return context;
};

const ToastProviderCore: React.FC<{ children: ReactNode }> = ({ children }) => {
  const { pushToast } = useToast();
  const dispatchToast = useCallback(
    ({
      closable,
      message,
      onClose,
      progress,
      shouldTimeout,
      timeout,
      title,
      variant,
    }: ToastParams) => {
      let toastTimeout = null;
      if (timeout !== undefined) {
        toastTimeout = timeout;
      } else if (shouldTimeout) {
        toastTimeout = TOAST_TIMEOUT;
      }

      return pushToast({
        // @ts-expect-error: data-cy doesn't exist as a prop on Toast but it will be propagated correctly.
        "data-cy": "toast",
        "data-variant": mapLeafyGreenVariantToToast[variant],
        description: <WordBreak>{message}</WordBreak>,
        dismissible: closable,
        onClose: closable ? onClose : undefined,
        progress,
        timeout: toastTimeout,
        title: title || mapLeafyGreenVariantToTitle[variant],
        variant,
      });
    },
    [pushToast],
  );

  const toastContext: ToastContextState = useMemo(() => {
    const defaultOptions = {
      onClose: () => {},
      shouldTimeout: true,
      title: "",
    };

    return {
      error: (message = "", closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          variant: Variant.Warning,
          ...defaultOptions,
          ...options,
        }),
      info: (message = "", closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          variant: Variant.Note,
          ...defaultOptions,
          ...options,
        }),
      progress: (message = "", progress = 0.5, closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          progress,
          variant: Variant.Progress,
          ...defaultOptions,
          ...options,
        }),
      success: (message = "", closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          variant: Variant.Success,
          ...defaultOptions,
          ...options,
        }),
      warning: (message = "", closable = true, options = {}) =>
        dispatchToast({
          closable,
          message,
          variant: Variant.Important,
          ...defaultOptions,
          ...options,
        }),
    };
  }, [dispatchToast]);

  return (
    <ToastContext.Provider value={toastContext}>
      {children}
    </ToastContext.Provider>
  );
};

const ToastProvider: React.FC<{
  children?: ReactNode;
  portalClassName?: string;
}> = ({ children, portalClassName }) => (
  <LGToastProvider portalClassName={portalClassName}>
    <ToastProviderCore>{children}</ToastProviderCore>
  </LGToastProvider>
);

export { ToastProvider, useToastContext };

export enum TaskStatus {
  Inactive = "inactive",

  // TaskUnstarted is assigned to a display task after cleaning up one of
  // its execution tasks. This indicates that the display task is
  // pending a rerun
  Unstarted = "unstarted",

  // TaskUndispatched indicates either
  //  1. a task is not scheduled to run (when Task.Activated == false)
  //  2. a task is scheduled to run (when Task.Activated == true)
  Undispatched = "undispatched",
  WillRun = "will-run",
  Unscheduled = "unscheduled",

  // TaskStarted indicates a task is currently running
  Started = "started",

  // TaskDispatched indicates that an agent has received the task, but
  // the agent has not yet told Evergreen that it's running the task
  Dispatched = "dispatched",

  // This is a temporary status which is the same as undispatched, but
  // with the additional info that it's waiting for a dependency
  Pending = "pending",

  // The statuses below indicate that a task has finished.
  Succeeded = "success",

  // These statuses indicate that the task failed, and it is likely a problem
  // with the code being tested
  Failed = "failed",
  TestTimedOut = "test-timed-out",
  TaskTimedOut = "task-timed-out",

  // These statuses indicate that the task failed, and it is likely a problem
  // with the systems running the task
  SetupFailed = "setup-failed",
  SystemFailed = "system-failed",
  SystemTimedOut = "system-timed-out",
  SystemUnresponsive = "system-unresponsive",

  // This status means that the task will not run because a dependency was
  // not satisfied
  Blocked = "blocked",
  Aborted = "aborted",

  KnownIssue = "known-issue",
}

// Task status sorted in order of "relevance", with the most likely actionable at the top.
export const SortedTaskStatus = [
  TaskStatus.Failed,
  TaskStatus.TestTimedOut,
  TaskStatus.TaskTimedOut,
  TaskStatus.KnownIssue,
  TaskStatus.SetupFailed,
  TaskStatus.SystemFailed,
  TaskStatus.SystemTimedOut,
  TaskStatus.SystemUnresponsive,
  TaskStatus.Started,
  TaskStatus.Dispatched,
  TaskStatus.Succeeded,
  TaskStatus.Undispatched,
  TaskStatus.WillRun,
  TaskStatus.Aborted,
  TaskStatus.Blocked,
  TaskStatus.Unscheduled,
];

export enum TaskStatusUmbrella {
  Failed = "failed-umbrella",
  SystemFailure = "system-failure-umbrella",
  Running = "running-umbrella",
  Undispatched = "undispatched-umbrella",
  Scheduled = "scheduled-umbrella",
}

export enum TestStatus {
  Fail = "fail",
  Skip = "skip",
  SilentFail = "silentfail",
  Pass = "pass",
}

