import preview from "#.storybook/preview";
import { TaskStatus } from "../../../types/task";
import TaskStatusBadge from "./index";

const meta = preview.meta({
  component: TaskStatusBadge,
  tags: ["ai-generated"],
});

export default meta;

export const Succeeded = meta.story({
  args: {
    status: TaskStatus.Succeeded,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("Succeeded");
    await expect(badge).toBeVisible();
  },
});

export const Failed = meta.story({
  args: {
    status: TaskStatus.Failed,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("Failed");
    await expect(badge).toBeVisible();
  },
});

export const Running = meta.story({
  args: {
    status: TaskStatus.Started,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("Running");
    await expect(badge).toBeVisible();
  },
});

export const SystemFailed = meta.story({
  args: {
    status: TaskStatus.SystemFailed,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("System Failed");
    await expect(badge).toBeVisible();
  },
});

export const WithTaskCount = meta.story({
  args: {
    status: TaskStatus.Failed,
    taskCount: 5,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("5 Failed");
    await expect(badge).toBeVisible();
  },
});

export const CssCheck = meta.story({
  args: {
    status: TaskStatus.Succeeded,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("Succeeded");
    // LeafyGreen Badge with Green variant should have a green-ish background
    const style = getComputedStyle(badge);
    // The badge should have non-default styling from LeafyGreen
    await expect(style.fontFamily).not.toBe("");
    await expect(style.display).not.toBe("none");
    // Verify the green variant badge has a background color set
    await expect(style.backgroundColor).not.toBe("");
  },
});

