        localAuthRoute="/login"
        remoteAuthURL="http://localhost:9090/login"
        shouldUseLocalAuth
      >
        <Story />
      </AuthProvider>
    ),
  ],
};

export default meta;
type Story = StoryObj<typeof LoginPage>;

export const Default: Story = {
  args: {
