516→								<span title="${s.status}" style="width: 8px; height: 8px; border-radius: 50%; background-color: ${s.status === 'connected' ? '#10b981' : s.status === 'unknown' ? '#6b7280' : '#ef4444'}; margin-right: 0.5rem;"></span>
517→								${s.name}
518→							</div>`,
519→					)
520→					.join('') +
521→				'</div>';
522→			metadataCards.push({
523→				title: 'MCP Servers',
524→				html: mcpServersHtml,
525→			});
526→		} else {
