536→			metadataCards.push({
537→				title: 'Turns',
538→				value: resultTurn.num_turns,
539→			});
540→		}
541→
542→		if (messageTokens > 0) {
543→			metadataCards.push({
544→				title: 'Total Message Tokens',
545→				value: messageTokens.toLocaleString(),
546→			});
547→		}
548→	}
