  1→import { addBreadcrumb, Breadcrumb, isInitialized } from "@sentry/react";
  2→import { initializeSentry, sendError as sentrySendError } from "../sentry";
  3→import { SentryBreadcrumbTypes, ErrorInput } from "../sentry/types";
  4→import { validateMetadata } from "../sentry/utils";
  5→
  6→interface reportErrorResult {
  7→  /** Report error as severe. This will cause an alert on our alerting infrastructure. Use this for critical errors. */
  8→  severe: () => void;
  9→  /** Report error as a warning. This will log the error to our infrastructure and will only alert if there is a spike. Use this for most errors. */
 10→  warning: () => void;
 11→}
 12→
 13→type ErrorMetadata = {
 14→  fingerprint?: ErrorInput["fingerprint"];
 15→  tags?: ErrorInput["tags"];
 16→  context?: ErrorInput["context"];
 17→};
 18→
 19→/**
 20→ * `reportError` is a utility function that reports an error to Sentry if Sentry is initialized.
 21→ * If Sentry is not initialized, it logs the error to the console.
 22→ * @param err - The error to report.
 23→ * @param param1 - The metadata for the error.
 24→ * @param param1.context - The context for the error.
 25→ * @param param1.fingerprint - The fingerprint for the error. This is used to group errors together.
 26→ * @param param1.tags - Any tags to attach to the error.
 27→ * @returns - An object with two functions: `severe` and `warning`. These functions report the error with different severities.
 28→ */
 29→const reportError = (
 30→  err: Error,
 31→  { context, fingerprint, tags }: ErrorMetadata = {},
 32→): reportErrorResult => {
 33→  if (!isInitialized()) {
 34→    return {
 35→      severe: () => {
 36→        console.error({ err, severity: "severe", context, fingerprint, tags });
 37→      },
 38→      warning: () => {
 39→        console.error({ err, severity: "warning", context, fingerprint, tags });
 40→      },
 41→    };
 42→  }
 43→
 44→  return {
 45→    severe: () => {
 46→      sentrySendError({
 47→        context,
 48→        err,
 49→        fingerprint,
 50→        severity: "error",
 51→        tags,
 52→      });
 53→    },
 54→    warning: () => {
 55→      sentrySendError({
 56→        context,
 57→        err,
 58→        fingerprint,
 59→        severity: "warning",
 60→        tags,
 61→      });
 62→    },
 63→  };
 64→};
 65→
 66→/**
 67→ * `leaveBreadcrumb` logs messages that are useful for debugging and will appear in the sentry timeline.
 68→ * @param message - The message to log.
 69→ * @param metadata - Any metadata to attach to the breadcrumb.
 70→ * @param type - The type of breadcrumb to log. This determines the icon that appears in the timeline.
 71→ */
 72→const leaveBreadcrumb = (
 73→  message: string,
 74→  metadata: Breadcrumb["data"],
 75→  type: SentryBreadcrumbTypes,
 76→) => {
 77→  if (!isInitialized()) {
 78→    console.debug({ message, metadata, type });
 79→  } else {
 80→    const bc: Breadcrumb = {
 81→      message,
 82→      data: validateMetadata(metadata, type),
 83→      // Divide date by 1000 because Sentry wants the timestamp in RFC 3339, or seconds (not milliseconds!) since the Unix epoch.
 84→      timestamp: new Date().getTime() / 1000,
 85→      type,
 86→    };
 87→    addBreadcrumb(bc);
 88→  }
 89→};
 90→
 91→/**
 92→ * `initializeErrorHandling` initializes error handling for the application.
 93→ * This function should be called once in the application's lifecycle.
 94→ * It initializes Sentry for production builds.
 95→ * @param options - The options for initializing error handling.
 96→ * @param options.isProductionBuild - Whether the application is a production build.
 97→ * @param options.sentryDSN - The Sentry DSN.
 98→ * @param options.environment - The environment the application is running in.
 99→ */
100→const initializeErrorHandling = ({
101→  environment,
102→  isProductionBuild,
103→  sentryDSN,
104→}: {
105→  isProductionBuild: boolean;
106→  sentryDSN: string;
107→  environment: string;
108→}) => {
109→  if (!isProductionBuild) {
110→    return;
111→  }
112→
113→  if (!isInitialized()) {
114→    initializeSentry({
115→      debug: !isProductionBuild,
116→      sentryDSN: sentryDSN,
117→      environment: environment,
118→    });
119→  }
120→};
121→
122→export {
123→  initializeErrorHandling,
124→  leaveBreadcrumb,
125→  reportError,
126→  SentryBreadcrumbTypes,
127→};
128→

  1→import type { Context } from "@sentry/core";
  2→import {
  3→  captureException,
  4→  init,
  5→  setTags,
  6→  withScope,
  7→  type Scope,
  8→  type SeverityLevel,
  9→} from "@sentry/react";
 10→import { ErrorInput } from "./types";
 11→import { processHtmlAttributes } from "./utils";
 12→
 13→/**
 14→ * `initializeSentry` initializes Sentry with the provided configuration. DO NOT call this function directly.
 15→ * This function should be called once in the application's lifecycle.
 16→ * @param param0 - The properties of the Sentry initialization object
 17→ * @param param0.debug - Whether to enable debug mode
 18→ * @param param0.environment - The environment the application is running in
 19→ * @param param0.sentryDSN - The Sentry DSN
 20→ */
 21→const initializeSentry = ({
 22→  debug,
 23→  environment,
 24→  sentryDSN,
 25→}: {
 26→  sentryDSN?: string;
 27→  environment?: string;
 28→  debug?: boolean;
 29→}) => {
 30→  try {
 31→    init({
 32→      beforeBreadcrumb: (breadcrumb, hint) => {
 33→        if (breadcrumb?.category?.startsWith("ui")) {
 34→          const { target } = hint?.event ?? {};
 35→          if (target?.dataset?.cy) {
 36→            breadcrumb.message = `${target.tagName.toLowerCase()}[data-cy="${target.dataset.cy}"]`;
 37→          }
 38→          breadcrumb.data = processHtmlAttributes(target);
 39→        }
 40→        return breadcrumb;
 41→      },
 42→      // Don't send errors from unauthenticated users
 43→      beforeSend: (event) => (event.user?.id ? event : null),
 44→      debug: debug,
 45→      dsn: sentryDSN,
 46→      environment: environment || "development",
 47→      maxValueLength: 500,
 48→      normalizeDepth: 5,
 49→    });
 50→  } catch (e) {
 51→    console.error("Failed to initialize Sentry", e);
 52→  }
 53→};
 54→
 55→/**
 56→ * `sendError` sends an error to Sentry. Do not call this function directly.
 57→ * @param param0 - The error input object's properties
 58→ * @param param0.context - The context object to attach to the error
 59→ * @param param0.err - The error object to send
 60→ * @param param0.fingerprint - The fingerprint to group errors by
 61→ * @param param0.severity - The severity level of the error
 62→ * @param param0.tags - The tags to attach to the error
 63→ */
 64→const sendError = ({
 65→  context,
 66→  err,
 67→  fingerprint,
 68→  severity,
 69→  tags,
 70→}: ErrorInput) => {
 71→  withScope((scope) => {
 72→    setScope(scope, { level: severity, context });
 73→    if (fingerprint) {
 74→      // A custom fingerprint allows for more intelligent grouping
 75→      scope.setFingerprint(fingerprint);
 76→    }
 77→
 78→    if (tags) {
 79→      // Apply tags, which are a searchable/filterable property
 80→      setTags(tags);
 81→    }
 82→
 83→    captureException(err);
 84→  });
 85→};
 86→
 87→type ScopeOptions = {
 88→  level?: SeverityLevel;
 89→  context?: Context;
 90→};
 91→
 92→const setScope = (scope: Scope, { context, level }: ScopeOptions = {}) => {
 93→  const userId = localStorage.getItem("userId") ?? undefined;
 94→  scope.setUser({ id: userId });
 95→
 96→  if (level) scope.setLevel(level);
 97→  if (context) scope.setContext("metadata", context);
 98→};
 99→
100→export { initializeSentry, setScope, sendError };
