  1→import { HoneycombWebSDK } from "@honeycombio/opentelemetry-web";
  2→import {
  3→  getWebAutoInstrumentations,
  4→  InstrumentationConfigMap,
  5→} from "@opentelemetry/auto-instrumentations-web";
  6→import ReactRouterSpanProcessor from "./ReactRouterSpanProcessor";
  7→import { RouteConfig } from "./ReactRouterSpanProcessor/types";
  8→import { detectGraphqlQuery } from "./utils";
  9→/**
 10→ * Configuration object for the Honeycomb SDK.
 11→ */
 12→interface HoneycombConfig {
 13→  /** The service name for the app we are running e.g. spruce or parsley */
 14→  serviceName: string;
 15→  /** The endpoint for the Honeycomb SDK to send traces to if we are not using the default */
 16→  endpoint: string;
 17→  /** The url for our Honeycomb instrumented server to connect frontend and backend traces together */
 18→  backendURL?: string;
 19→  /** Whether to enable debug mode in the Honeycomb SDK this will enable additional logging and print links to traces */
 20→  debug: boolean;
 21→  /** The INGEST key for the Honeycomb SDK */
 22→  ingestKey: string;
 23→  /** The environment we are running in */
 24→  environment: string;
 25→  /** A config representing all routes the app can have */
 26→  routeConfig: RouteConfig;
 27→  /** A version number indicating which release this is */
 28→  appVersion: string;
 29→}
 30→
 31→/**
 32→ * Initializes the Honeycomb SDK with the provided configuration.
 33→ * @param config - The configuration object for the Honeycomb SDK.
 34→ * @param config.ingestKey - The Honeycomb INGEST API key.
 35→ * @param config.backendURL - The backend URL.
 36→ * @param config.debug - Whether to start the SDK in debug mode.
 37→ * @param config.serviceName - The name of the service.
 38→ * @param config.endpoint - The endpoint for the Honeycomb SDK to send traces to if we are not using the default.
 39→ * @param config.environment - The environment we are running in.
 40→ * @param config.routeConfig - A config representing all routes the app can have.
 41→ * @param config.appVersion - A version number indicating which release this is.
 42→ */
 43→const initializeHoneycomb = ({
 44→  appVersion,
 45→  backendURL,
 46→  debug,
 47→  endpoint,
 48→  environment,
 49→  ingestKey,
 50→  routeConfig,
 51→  serviceName,
 52→}: HoneycombConfig) => {
 53→  if (debug && (!ingestKey || !endpoint)) {
 54→    console.warn(
 55→      "Honeycomb INGEST API key or a collector endpoint was not provided. Starting SDK in debug mode. No traces will be sent.",
 56→    );
 57→    return;
 58→  }
 59→  if (!ingestKey && !endpoint) {
 60→    console.error(
 61→      "Honeycomb INGEST API key or a collector endpoint is required to start the SDK in production mode.",
 62→    );
 63→  } else {
 64→    try {
 65→      const userId = localStorage.getItem("userId") ?? undefined;
 66→      const webAutoInstrumentationConfig: InstrumentationConfigMap = {
 67→        "@opentelemetry/instrumentation-document-load": {
 68→          ignoreNetworkEvents: true,
 69→        },
 70→        "@opentelemetry/instrumentation-fetch": {
 71→          // Add GraphQL operation name as an attribute to HTTP traces.
 72→          applyCustomAttributesOnSpan: (span, request) => {
 73→            if (span && request) {
 74→              const { body } = request;
 75→              if (!body || typeof body !== "string") {
 76→                return;
 77→              }
 78→              const graphqlQuery = detectGraphqlQuery(body);
 79→              if (graphqlQuery) {
 80→                span.setAttribute(
 81→                  "graphql.operation_name",
 82→                  graphqlQuery.operationName,
 83→                );
 84→                span.setAttribute("graphql.query_type", graphqlQuery.queryType);
 85→              }
 86→            }
 87→          },
 88→          // Allow connecting frontend & backend traces.
 89→          propagateTraceHeaderCorsUrls: [new RegExp(backendURL || "")],
 90→        },
 91→      };
 92→
 93→      const honeycombSdk = new HoneycombWebSDK({
 94→        debug,
 95→        endpoint,
 96→        instrumentations: [
 97→          getWebAutoInstrumentations(webAutoInstrumentationConfig),
 98→        ],
 99→        // Add attributes to all traces.
100→        resourceAttributes: {
101→          "user.id": userId,
102→          environment,
103→          app_version: appVersion,
104→        },
105→        localVisualizations: debug,
106→        serviceName,
107→        apiKey: ingestKey,
108→        spanProcessor: new ReactRouterSpanProcessor(routeConfig),
109→      });
110→      honeycombSdk.start();
111→    } catch (e) {
112→      console.error(`Could not start Honeycomb SDK: ${e}`);
113→    }
114→  }
115→};
116→
117→export { initializeHoneycomb };
118→

