import { http, HttpResponse } from "msw";

export const mswHandlers = [
  // AuthProvider checks auth by posting to /graphql/query
  http.post("*/graphql/query", () =>
    HttpResponse.json({
      data: {
        user: {
          userId: "mock-user-id",
        },
      },
    }),
  ),
  // AuthProvider local login
  http.post("*/login", () => new HttpResponse(null, { status: 200 })),
  // AuthProvider logout
  http.get("*/logout", () => new HttpResponse(null, { status: 200 })),
];

import { Global } from "@emotion/react";
import { MemoryRouter } from "react-router-dom";
import { initialize, mswLoader } from "msw-storybook-addon";
import { definePreview } from "storybook/preview";
import {
  resetStyles,
  bodyStyles,
} from "../src/components/styles/globalStyles";
import { fontStyles } from "../src/components/styles/fonts";
import { mswHandlers } from "./msw-handlers";

initialize({
  onUnhandledRequest: "bypass",
});

export default definePreview({
  decorators: [
    (Story) => (
      <>
        <Global styles={[resetStyles, bodyStyles, fontStyles]} />
        <MemoryRouter>
          <Story />
        </MemoryRouter>
      </>
    ),
  ],
  loaders: [mswLoader],
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
    a11y: {
      test: "todo",
    },
    msw: {
      handlers: mswHandlers,
    },
  },
});

