import { expect } from "storybook/test";
import preview from "#.storybook/preview";
import Accordion, { AccordionCaretAlign, AccordionCaretIcon } from "./index";

const meta = preview.meta({
  component: Accordion,
  tags: ["ai-generated"],
});

export default meta;

export const Default = meta.story({
  args: {
    title: "Accordion Title",
    children: "This is the accordion content that is hidden by default.",
  },
  play: async ({ canvas, userEvent }) => {
    const toggle = canvas.getByRole("button", { name: /accordion icon/i });
    await expect(toggle).toBeVisible();
    await expect(canvas.getByText("Accordion Title")).toBeVisible();
    // Content should be collapsed by default
    const container = canvas.getByText(
      "This is the accordion content that is hidden by default.",
    );
    await expect(container).toBeInTheDocument();
    // Click to expand
    await userEvent.click(toggle);
    const collapseContainer = canvas.getByLabelText(/accordion icon/i);
    await expect(collapseContainer).toBeVisible();
  },
});

export const DefaultOpen = meta.story({
  args: {
    title: "Open Accordion",
    defaultOpen: true,
    children: "This content is visible by default.",
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText("Open Accordion")).toBeVisible();
    await expect(
      canvas.getByText("This content is visible by default."),
    ).toBeVisible();
  },
});

export const WithSubtitle = meta.story({
  args: {
    title: "Accordion With Subtitle",
    subtitle: "This is a subtitle below the title",
    defaultOpen: true,
    caretAlign: AccordionCaretAlign.Start,
    caretIcon: AccordionCaretIcon.Caret,
    children: "Content with subtitle and caret icon.",
  },
  play: async ({ canvas }) => {
    await expect(
      canvas.getByText("Accordion With Subtitle"),
    ).toBeVisible();
    await expect(
      canvas.getByText("This is a subtitle below the title"),
    ).toBeVisible();
    await expect(
      canvas.getByText("Content with subtitle and caret icon."),
    ).toBeVisible();
  },
});

import { expect } from "storybook/test";
import preview from "#.storybook/preview";
import { TaskStatus } from "../../../types/task";
import TaskStatusBadge from "./index";

const meta = preview.meta({
  component: TaskStatusBadge,
  tags: ["ai-generated"],
});

export default meta;

export const Succeeded = meta.story({
  args: {
    status: TaskStatus.Succeeded,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("Succeeded");
    await expect(badge).toBeVisible();
  },
});

export const Failed = meta.story({
  args: {
    status: TaskStatus.Failed,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("Failed");
    await expect(badge).toBeVisible();
  },
});

export const Running = meta.story({
  args: {
    status: TaskStatus.Started,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("Running");
    await expect(badge).toBeVisible();
  },
});

export const SystemFailed = meta.story({
  args: {
    status: TaskStatus.SystemFailed,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("System Failed");
    await expect(badge).toBeVisible();
  },
});

export const WithTaskCount = meta.story({
  args: {
    status: TaskStatus.Failed,
    taskCount: 5,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("5 Failed");
    await expect(badge).toBeVisible();
  },
});

export const CssCheck = meta.story({
  args: {
    status: TaskStatus.Succeeded,
  },
  play: async ({ canvas }) => {
    const badge = canvas.getByText("Succeeded");
    // LeafyGreen Badge with Green variant should have a green-ish background
    const style = getComputedStyle(badge);
    // The badge should have non-default styling from LeafyGreen
    await expect(style.fontFamily).not.toBe("");
    await expect(style.display).not.toBe("none");
    // Verify the green variant badge has a background color set
    await expect(style.backgroundColor).not.toBe("");
  },
