// Polyfill Buffer for browser environment (needed by @emotion/server via @leafygreen-ui/tokens)
if (typeof globalThis.Buffer === "undefined") {
  // Minimal Buffer polyfill - only needs to exist so buffer-from doesn't throw
  // @ts-expect-error: minimal polyfill
  globalThis.Buffer = {
    isBuffer: () => false,
    from: (data: unknown) => {
      if (typeof data === "string") {
        return new TextEncoder().encode(data);
      }
      return new Uint8Array();
    },
    alloc: (size: number) => new Uint8Array(size),
    allocUnsafe: (size: number) => new Uint8Array(size),
    isEncoding: () => true,
  };
}

// Stub for @emotion/server to prevent Node.js modules (buffer, events) from being loaded in browser
export default {};
export const extractCritical = () => ({ html: "", css: "", ids: [] });
export const extractCriticalToChunks = () => ({
  html: "",
  styles: [],
});
export const renderStylesToString = (html: string) => html;
export const renderStylesToNodeStream = () => null;

