import type { Meta, StoryObj } from "@storybook/react-vite";
import { expect, fn } from "storybook/test";
import Pagination from "./index";

const meta: Meta<typeof Pagination> = {
  component: Pagination,
  tags: ["ai-generated"],
};

export default meta;
type Story = StoryObj<typeof Pagination>;

export const FirstPage: Story = {
  args: {
    currentPage: 0,
    totalResults: 50,
    pageSize: 10,
    onChange: fn(),
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText("1 / 5")).toBeVisible();
    // Previous button should be disabled on first page
    const buttons = canvas.getAllByRole("button");
    const prevButton = buttons[0];
    await expect(prevButton).toHaveAttribute("aria-disabled", "true");
  },
};

export const MiddlePage: Story = {
  args: {
    currentPage: 2,
    totalResults: 50,
    pageSize: 10,
    onChange: fn(),
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText("3 / 5")).toBeVisible();
  },
};

export const LastPage: Story = {
  args: {
    currentPage: 4,
    totalResults: 50,
    pageSize: 10,
    onChange: fn(),
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText("5 / 5")).toBeVisible();
    // Next button should be disabled on last page
    const buttons = canvas.getAllByRole("button");
    const nextButton = buttons[buttons.length - 1];
    await expect(nextButton).toHaveAttribute("aria-disabled", "true");
  },
};

import type { Meta, StoryObj } from "@storybook/react-vite";
import { Button } from "@leafygreen-ui/button";
import { useRef, useState } from "react";
import { expect, fn, waitFor } from "storybook/test";
import { within } from "storybook/test";
import Popconfirm from "./index";

const meta: Meta<typeof Popconfirm> = {
  component: Popconfirm,
  tags: ["ai-generated"],
};

export default meta;
type Story = StoryObj<typeof Popconfirm>;

export const Default: Story = {
  render: () => {
    const [open, setOpen] = useState(false);
    const buttonRef = useRef<HTMLButtonElement>(null);
    return (
      <div style={{ padding: "100px" }}>
        <Button ref={buttonRef} onClick={() => setOpen(true)}>
          Delete Item
        </Button>
        <Popconfirm
          onConfirm={fn()}
          open={open}
          refEl={buttonRef.current ?? undefined}
          setOpen={setOpen}
        >
          Are you sure you want to delete this item?
        </Popconfirm>
      </div>
    );
  },
  play: async ({ canvas, canvasElement, userEvent }) => {
    const trigger = canvas.getByRole("button", { name: /delete item/i });
    await expect(trigger).toBeVisible();
    await userEvent.click(trigger);
    // Popconfirm renders in a portal, query from document
    const body = within(canvasElement.ownerDocument.body);
    await waitFor(() => {
      expect(
        body.getByText("Are you sure you want to delete this item?"),
      ).toBeVisible();
    });
    await expect(body.getByRole("button", { name: /yes/i })).toBeVisible();
    await expect(
      body.getByRole("button", { name: /cancel/i }),
    ).toBeVisible();
  },
};

export const CustomConfirmText: Story = {
  render: () => {
    const [open, setOpen] = useState(false);
    const buttonRef = useRef<HTMLButtonElement>(null);
    return (
      <div style={{ padding: "100px" }}>
        <Button ref={buttonRef} onClick={() => setOpen(true)}>
          Restart Task
        </Button>
        <Popconfirm
          confirmText="Restart"
          onConfirm={fn()}
          open={open}
          refEl={buttonRef.current ?? undefined}
          setOpen={setOpen}
        >
          Are you sure you want to restart this task?
        </Popconfirm>
      </div>
    );
  },
  play: async ({ canvas, canvasElement, userEvent }) => {
    const trigger = canvas.getByRole("button", { name: /restart task/i });
    await userEvent.click(trigger);
    const body = within(canvasElement.ownerDocument.body);
    await waitFor(() => {
      expect(body.getByRole("button", { name: /^restart$/i })).toBeVisible();
    });
  },
};

export const ConfirmDisabled: Story = {
  render: () => {
    const [open, setOpen] = useState(false);
    const buttonRef = useRef<HTMLButtonElement>(null);
    return (
      <div style={{ padding: "100px" }}>
        <Button ref={buttonRef} onClick={() => setOpen(true)}>
          Action
        </Button>
        <Popconfirm
          confirmDisabled
          onConfirm={fn()}
          open={open}
          refEl={buttonRef.current ?? undefined}
          setOpen={setOpen}
        >
          This action requires additional permissions.
        </Popconfirm>
      </div>
    );
  },
  play: async ({ canvas, canvasElement, userEvent }) => {
    const trigger = canvas.getByRole("button", { name: /^action$/i });
    await userEvent.click(trigger);
    const body = within(canvasElement.ownerDocument.body);
    await waitFor(() => {
      expect(
        body.getByText("This action requires additional permissions."),
      ).toBeVisible();
    });
    const confirmButton = body.getByRole("button", { name: /yes/i });
    await expect(confirmButton).toHaveAttribute("aria-disabled", "true");
  },
};

